exercise.solution:
function BookCard({ title, author, available }) {
  return (
    <div>
      <h3>{title}</h3>
      <p>{author}</p>
      <p>{available ? 'Available' : 'Checked out'}</p>
    </div>
  );
}

function App() {
  return (
    <div>
      <BookCard
        title="The Pragmatic Programmer"
        author="Andrew Hunt"
        available={true}
      />
      <BookCard
        title="Clean Code"
        author="Robert C. Martin"
        available={false}
      />
    </div>
  );
}

export default App;
